import { MakeLogicType, actions, afterMount, kea, listeners, path, reducers } from 'kea'
import { loaders } from 'kea-loaders'

import { teamLogic } from 'scenes/teamLogic'

import { mcpGatewayAuditCountsRetrieve, mcpGatewayAuditList } from '../generated/api'
import { AuditCountsApi, MCPAuditEventApi } from '../generated/api.schemas'

export type AuditQuickFilter = 'all' | 'agents' | 'approvals' | 'blocked'

const PAGE_SIZE = 10

function currentProjectId(): string {
    return String(teamLogic.values.currentTeamId)
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface gatewayAuditLogicValues {
    auditResponse: {
        count: number;
        results: MCPAuditEventApi[];
    };
    auditResponseLoading: boolean;
    counts: AuditCountsApi | null;
    countsLoading: boolean;
    page: number;
    quickFilter: AuditQuickFilter;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface gatewayAuditLogicActions {
    loadAudit: () => any;
    loadAuditFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadAuditSuccess: (auditResponse: {
        count: number;
        results: MCPAuditEventApi[];
    }, payload?: any) => {
        auditResponse: {
            count: number;
            results: MCPAuditEventApi[];
        };
        payload?: any;
    };
    loadCounts: () => any;
    loadCountsFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadCountsSuccess: (counts: AuditCountsApi, payload?: any) => {
        counts: AuditCountsApi;
        payload?: any;
    };
    setPage: (page: number) => {
        page: number;
    };
    setQuickFilter: (quickFilter: AuditQuickFilter) => {
        quickFilter: AuditQuickFilter;
    };
}

export type gatewayAuditLogicType = MakeLogicType<gatewayAuditLogicValues, gatewayAuditLogicActions>;

export const gatewayAuditLogic = kea<gatewayAuditLogicType>([
    path(['products', 'mcp_store', 'frontend', 'gateway', 'gatewayAuditLogic']),

    actions({
        setQuickFilter: (quickFilter: AuditQuickFilter) => ({ quickFilter }),
        setPage: (page: number) => ({ page }),
    }),

    reducers({
        quickFilter: ['all' as AuditQuickFilter, { setQuickFilter: (_, { quickFilter }) => quickFilter }],
        page: [1, { setPage: (_, { page }) => page, setQuickFilter: () => 1 }],
    }),

    loaders(({ values }) => ({
        auditResponse: [
            { count: 0, results: [] as MCPAuditEventApi[] } as { count: number; results: MCPAuditEventApi[] },
            {
                loadAudit: async () => {
                    const response = await mcpGatewayAuditList(currentProjectId(), {
                        quick_filter: values.quickFilter,
                        limit: PAGE_SIZE,
                        offset: (values.page - 1) * PAGE_SIZE,
                    })
                    return { count: response.count, results: response.results }
                },
            },
        ],
        counts: [
            null as AuditCountsApi | null,
            {
                loadCounts: async () => await mcpGatewayAuditCountsRetrieve(currentProjectId()),
            },
        ],
    })),

    listeners(({ actions }) => ({
        setQuickFilter: () => actions.loadAudit(),
        setPage: () => actions.loadAudit(),
    })),

    afterMount(({ actions }) => {
        actions.loadAudit()
        actions.loadCounts()
    }),
])

export { PAGE_SIZE as AUDIT_PAGE_SIZE }
